module top_module(
    input CLK,
    input EN,
    input TE,
    output ENCLK
);wire n2;
    reg EN_reg;

    always @ (posedge CLK, posedge TE) begin
        if (TE) begin
            EN_reg <= 1'b0;
        end else begin
            EN_reg <= EN;
        end
    end

    wire clk_gating_inverted = EN_reg & CLK;
    assign n2 = clk_gating_inverted;
    assign ENCLK = n2;

endmodule
